// Test stackalloc with Span<nint> and Span<nuint>
#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

// stackalloc nint
Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.Write("Span<nint>:  ");
foreach (var v in signedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

// stackalloc nuint
Span<nuint> unsignedSpan = stackalloc nuint[4];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.Write("Span<nuint>: ");
foreach (var v in unsignedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

Console.WriteLine("Success!");

